# PROGRESSIVE PLASTIC HINGE FORMATION  — 3D ISOMETRIC VIEWS
# =====================================================================
def _plot_hinge_frame_3d_v(ax, snap, n_pts):
    """Draw 3D frame with ACI 369.1M-17 hinge damage markers."""
    # structural member lines
    for et, (ni, nj) in _elem_nodes_v.items():
        xi, yi, zi = _node_xyz_v[ni]
        xj, yj, zj = _node_xyz_v[nj]
        ax.plot([xi, xj], [yi, yj], [zi, zj], 'k-', linewidth=1.0, zorder=1)

    # fixed-base markers (nodes at z = −2)
    for bn, (bx, by, bz) in _node_xyz_v.items():
        if bz < -1.5:
            ax.scatter([bx], [by], [bz], marker='^', s=45, c='k', zorder=4)

    # hinge markers at the two end integration points of each element
    _off = 0.08   # fractional offset inward along element axis
    for et, (ni, nj) in _elem_nodes_v.items():
        if et not in _ACI_ELEMENT_META:
            continue
        _meta = _ACI_ELEMENT_META[et]
        _phi_y = _member_phi_y(_meta['section'])
        _acc = _aci369_acceptance(_meta, snap.get('forces', {}).get(et, []))
        L = _elem_lengths_v[et]
        xi, yi, zi = _node_xyz_v[ni]
        xj, yj, zj = _node_xyz_v[nj]
        dx, dy, dz = xj - xi, yj - yi, zj - zi
        for sec_num, is_i_end in [(1, True), (n_pts, False)]:
            kappa   = snap['curvatures'][et][sec_num]
            phi_p   = max(0.0, kappa - _phi_y)
            theta_p = phi_p * 0.1 * L          # plastic rotation (rad)
            _category = _aci369_damage_category(theta_p, _acc)
            if _category is None:
                continue
            if is_i_end:
                hx, hy, hz = xi + _off*dx, yi + _off*dy, zi + _off*dz
            else:
                hx, hy, hz = xj - _off*dx, yj - _off*dy, zj - _off*dz
            color = ('gold' if _category == 'between IO and LS' else
                     'darkorange' if _category == 'between LS and CP' else 'red')
            size  = (55 if _category == 'between IO and LS' else
                     95 if _category == 'between LS and CP' else 135)
            ax.scatter([hx], [hy], [hz], c=color, s=size,
                       edgecolors='black', linewidths=0.6, zorder=5)


if _hinge_snapshots_v:
    _n_frames = len(_hinge_snapshots_v)

    fig_anim = plt.figure(figsize=(8.0, 7.0))
    _ax3d_anim = fig_anim.add_subplot(111, projection='3d')

    _legend_patches = [
        mpatches.Patch(facecolor='gold',       edgecolor='black',
                       label='ACI 369.1M-17: IO < \u03b8\u209a < LS'),
        mpatches.Patch(facecolor='darkorange',  edgecolor='black',
                       label='ACI 369.1M-17: LS \u2264 \u03b8\u209a < CP'),
        mpatches.Patch(facecolor='red',         edgecolor='black',
                       label='ACI 369.1M-17: \u03b8\u209a \u2265 CP'),
    ]
    fig_anim.legend(handles=_legend_patches, loc='lower center', ncol=3,
                    fontsize=8.5, bbox_to_anchor=(0.5, 0.0), framealpha=0.9)

    def _anim_init():
        _ax3d_anim.cla()
        _ax3d_anim.set_xlabel('x (m)', fontsize=7, labelpad=1)
        _ax3d_anim.set_ylabel('y (m)', fontsize=7, labelpad=1)
        _ax3d_anim.set_zlabel('z (m)', fontsize=7, labelpad=1)
        _ax3d_anim.tick_params(labelsize=5)
        _ax3d_anim.set_box_aspect([18.5, 14.0, 16.0])
        _ax3d_anim.view_init(elev=22, azim=-50)
        return []

    def _anim_update(frame_idx):
        snap = _hinge_snapshots_v[frame_idx]
        _ax3d_anim.cla()
        _plot_hinge_frame_3d_v(_ax3d_anim, snap, _n_int_pts_v)
        pct   = (snap['step'] / _n_frames) * 100
        title = (f"Step {snap['step']}/{_n_frames}  ({pct:.0f}% pushover)\n"
                 f"\u0394 = {snap['disp']:.1f} mm     V = {snap['shear']:.1f} kN")
        _ax3d_anim.set_title(title, fontsize=8)
        _ax3d_anim.set_xlabel('x (m)', fontsize=7, labelpad=1)
        _ax3d_anim.set_ylabel('y (m)', fontsize=7, labelpad=1)
        _ax3d_anim.set_zlabel('z (m)', fontsize=7, labelpad=1)
        _ax3d_anim.tick_params(labelsize=5)
        _ax3d_anim.set_box_aspect([18.5, 14.0, 16.0])
        _ax3d_anim.view_init(elev=22, azim=-50)
        fig_anim.suptitle('Progressive Plastic Hinge Formation — E2K Validation Model',
                          fontsize=10, fontweight='bold')
        return []

    _anim = _animation.FuncAnimation(
        fig_anim, _anim_update,
        frames=_n_frames,
        init_func=_anim_init,
        interval=50,       # ms per frame  (50 ms = 20 fps)
        repeat=True,
        blit=False,
    )
    plt.tight_layout(rect=[0, 0.09, 1, 0.96])

    # Save animation — requires ffmpeg (mp4) or pillow (gif)
    _anim_path = 'plastic_hinge_animation.mp4'
    _writer = _animation.FFMpegWriter(fps=20, bitrate=1800)
    print(f'Saving animation to {_anim_path} ...')
    _anim.save(_anim_path, writer=_writer, dpi=150)
    print(f'Animation saved: {_anim_path}')

    plt.show()
